export interface GlossaryEntry {
  term: string;
  definition: string;
  source: string;
  category: string;
  aliases?: string[];
}

export const GLOSSARY_CATEGORIES = [
  'MDR / IVDR',
  'FDA / 21 CFR',
  'ISO 13485 / QMS',
  'ISO 14971 / Risk Management',
  'IEC 62304 / Software',
  'IEC 62366 / Usability',
  'EHDS / PPWR / Sustainability',
  'MDCG Guidance',
  'Harmonised Standards',
  'General Regulatory',
] as const;

export const regulatoryGlossary: GlossaryEntry[] = [
  // ─── MDR / IVDR ────────────────────────────────────────────────
  { term: 'MDR', definition: 'Medical Device Regulation (EU) 2017/745 — the primary EU regulation governing the design, manufacture, and distribution of medical devices. Replaces the Medical Devices Directive (MDD) 93/42/EEC.', source: 'EU 2017/745', category: 'MDR / IVDR', aliases: ['Medical Device Regulation'] },
  { term: 'IVDR', definition: 'In Vitro Diagnostic Regulation (EU) 2017/746 — the EU regulation governing in vitro diagnostic medical devices. Replaces Directive 98/79/EC.', source: 'EU 2017/746', category: 'MDR / IVDR', aliases: ['In Vitro Diagnostic Regulation'] },
  { term: 'Notified Body', definition: 'An organization designated by an EU Member State to assess the conformity of certain products before being placed on the market. For medical devices, Notified Bodies audit QMS and review technical documentation.', source: 'MDR Art. 2(42)', category: 'MDR / IVDR', aliases: ['NB'] },
  { term: 'GSPR', definition: 'General Safety and Performance Requirements — the essential requirements listed in MDR Annex I that all medical devices must satisfy. Covers safety, performance, design, labelling, and information requirements.', source: 'MDR Annex I', category: 'MDR / IVDR', aliases: ['General Safety and Performance Requirements', 'Essential Requirements'] },
  { term: 'Authorised Representative', definition: 'A natural or legal person established in the EU who has received and accepted a written mandate from a manufacturer located outside the EU to act on behalf of that manufacturer in relation to specified tasks under MDR.', source: 'MDR Art. 2(32)', category: 'MDR / IVDR', aliases: ['AR', 'EC REP', 'European Authorised Representative'] },
  { term: 'EUDAMED', definition: 'European Database on Medical Devices — the EU\'s centralised IT system for medical device registration, UDI, certificates, clinical investigations, vigilance, and market surveillance.', source: 'MDR Art. 33', category: 'MDR / IVDR' },
  { term: 'UDI', definition: 'Unique Device Identification — a system of product identification using a standardised, internationally accepted system. Consists of UDI-DI (device identifier) and UDI-PI (production identifier).', source: 'MDR Art. 27', category: 'MDR / IVDR', aliases: ['Unique Device Identification'] },
  { term: 'UDI-DI', definition: 'UDI Device Identifier — a unique numeric or alphanumeric code specific to a model of device. Serves as the primary key for device identification in regulatory databases.', source: 'MDR Art. 27', category: 'MDR / IVDR', aliases: ['Device Identifier'] },
  { term: 'UDI-PI', definition: 'UDI Production Identifier — a numeric or alphanumeric code that identifies the unit of device production (lot/batch, serial number, expiry date, manufacturing date).', source: 'MDR Art. 27', category: 'MDR / IVDR', aliases: ['Production Identifier'] },
  { term: 'Basic UDI-DI', definition: 'The primary identifier of a device model that serves as the main key for records in the UDI database. It is the identity of a device model regardless of packaging or configuration.', source: 'MDR Art. 29', category: 'MDR / IVDR' },
  { term: 'Clinical Evaluation', definition: 'A systematic and planned process to continuously generate, collect, analyse, and assess the clinical data pertaining to a device to verify safety and performance, including clinical benefits.', source: 'MDR Art. 61', category: 'MDR / IVDR', aliases: ['CE', 'Clinical Evaluation Report', 'CER'] },
  { term: 'PMCF', definition: 'Post-Market Clinical Follow-up — a continuous process to actively collect and evaluate clinical data from the use of a CE-marked device on the market.', source: 'MDR Art. 61(11)', category: 'MDR / IVDR', aliases: ['Post-Market Clinical Follow-up'] },
  { term: 'PMS', definition: 'Post-Market Surveillance — a systematic proactive process to collect and review experience gained from devices placed on the market, to identify the need for corrective or preventive actions.', source: 'MDR Art. 83', category: 'MDR / IVDR', aliases: ['Post-Market Surveillance'] },
  { term: 'PSUR', definition: 'Periodic Safety Update Report — a document that manufacturers of Class IIa, IIb, and III devices must prepare and submit summarising PMS data, including trend analysis and risk-benefit conclusions.', source: 'MDR Art. 86', category: 'MDR / IVDR', aliases: ['Periodic Safety Update Report'] },
  { term: 'PRRC', definition: 'Person Responsible for Regulatory Compliance — a qualified individual within a manufacturer\'s organisation responsible for ensuring regulatory compliance. Must meet education and experience requirements of MDR Art. 15.', source: 'MDR Art. 15', category: 'MDR / IVDR', aliases: ['Person Responsible for Regulatory Compliance'] },
  { term: 'Declaration of Conformity', definition: 'A document (MDR Annex IV) in which the manufacturer declares that the device meets the applicable requirements of the regulation. Must be kept up to date and available to authorities.', source: 'MDR Art. 19', category: 'MDR / IVDR', aliases: ['DoC', 'EU Declaration of Conformity'] },
  { term: 'Technical Documentation', definition: 'The complete set of documents demonstrating that a device meets the applicable GSPRs, including design, manufacturing, risk management, clinical data, labelling, and PMS. Detailed in MDR Annexes II and III.', source: 'MDR Annex II/III', category: 'MDR / IVDR', aliases: ['Technical File', 'Design Dossier'] },
  { term: 'Vigilance', definition: 'The system for recording, reporting, and assessing serious incidents and field safety corrective actions related to medical devices placed on the EU market.', source: 'MDR Art. 87-92', category: 'MDR / IVDR' },
  { term: 'Serious Incident', definition: 'An incident that directly or indirectly led to, might have led to, or might lead to the death or serious deterioration of health of a patient, user, or other person.', source: 'MDR Art. 2(65)', category: 'MDR / IVDR' },
  { term: 'FSCA', definition: 'Field Safety Corrective Action — any corrective action taken by a manufacturer for technical or medical reasons to prevent or reduce risk of a serious incident related to a device made available on the market.', source: 'MDR Art. 2(68)', category: 'MDR / IVDR', aliases: ['Field Safety Corrective Action'] },
  { term: 'FSN', definition: 'Field Safety Notice — a communication sent by the manufacturer to users/customers about a Field Safety Corrective Action, informing them of the action and any steps they need to take.', source: 'MDR Art. 89(8)', category: 'MDR / IVDR', aliases: ['Field Safety Notice'] },
  { term: 'Conformity Assessment', definition: 'The process demonstrating whether a device meets the applicable requirements of MDR. The assessment route depends on device classification and may involve a Notified Body.', source: 'MDR Art. 52', category: 'MDR / IVDR' },
  { term: 'Classification Rules', definition: 'A set of rules (MDR Annex VIII) based on intended purpose, body contact duration, invasiveness, and active nature that determine the risk class (I, IIa, IIb, III) of a medical device.', source: 'MDR Annex VIII', category: 'MDR / IVDR' },
  { term: 'Implant Card', definition: 'An information document provided to patients who receive an implantable device, containing device identification, warnings, and expected lifetime information.', source: 'MDR Art. 18', category: 'MDR / IVDR' },
  { term: 'Summary of Safety and Clinical Performance', definition: 'A publicly available document for Class III and implantable devices summarising safety and clinical performance data. Updated at least annually by the manufacturer.', source: 'MDR Art. 32', category: 'MDR / IVDR', aliases: ['SSCP'] },
  { term: 'Economic Operator', definition: 'A manufacturer, authorised representative, importer, or distributor. Each has specific regulatory obligations under MDR.', source: 'MDR Art. 2(35)', category: 'MDR / IVDR' },
  { term: 'Importer', definition: 'A natural or legal person established in the EU who places a device from a third country on the EU market. Has specific verification and record-keeping obligations.', source: 'MDR Art. 2(33)', category: 'MDR / IVDR' },
  { term: 'Sponsor', definition: 'An individual, company, institution, or organisation that takes responsibility for the initiation, management, and financing of a clinical investigation.', source: 'MDR Art. 2(49)', category: 'MDR / IVDR' },
  { term: 'Clinical Investigation', definition: 'A systematic investigation involving human subjects undertaken to assess the safety or performance of a device. Subject to approval by ethics committees and competent authorities.', source: 'MDR Art. 62-82', category: 'MDR / IVDR' },
  { term: 'Intended Purpose', definition: 'The use for which a device is intended according to the data supplied by the manufacturer on the label, in IFU, and in promotional or sales materials. This is the MDR/EU term; the FDA equivalent is "Intended Use" (21 CFR 801). While functionally similar, the regulatory context and documentation requirements differ by jurisdiction.', source: 'MDR Art. 2(12)', category: 'MDR / IVDR' },
  { term: 'Performance Evaluation', definition: 'The assessment and analysis of data to establish or verify the scientific validity, analytical and clinical performance of an IVD device.', source: 'IVDR Art. 56', category: 'MDR / IVDR' },
  { term: 'Companion Diagnostic', definition: 'An IVD device essential for the safe and effective use of a corresponding medicinal product, used to identify patients most likely to benefit or be at risk.', source: 'IVDR Art. 2(7)', category: 'MDR / IVDR', aliases: ['CDx'] },
  { term: 'Common Specifications', definition: 'Technical and/or clinical requirements (adopted as implementing acts) that provide a means of complying with GSPRs or specific obligations. Formerly known as Common Technical Specifications (CTS) for IVDs.', source: 'MDR Art. 9', category: 'MDR / IVDR', aliases: ['CS'] },
  { term: 'Legacy Device', definition: 'A device lawfully placed on the market under the previous Directives (MDD/AIMDD/IVDD) that continues to be made available during the MDR/IVDR transition period.', source: 'MDR Art. 120', category: 'MDR / IVDR' },
  { term: 'Transition Period', definition: 'The timeframe during which devices certified under MDD/IVDD may continue to be placed on the market while transitioning to MDR/IVDR requirements. Extended multiple times by the EU.', source: 'MDR Art. 120', category: 'MDR / IVDR' },
  { term: 'Single-Use Device', definition: 'A device intended to be used on one individual during a single procedure. Reprocessing of single-use devices is regulated under MDR Art. 17.', source: 'MDR Art. 2(8)', category: 'MDR / IVDR' },
  { term: 'System/Procedure Pack', definition: 'A combination of devices and possibly other products packaged together and placed on the market for a specific medical purpose. The assembler has specific MDR obligations.', source: 'MDR Art. 22', category: 'MDR / IVDR' },
  { term: 'Competent Authority', definition: 'The national authority in each EU Member State responsible for the implementation and enforcement of MDR/IVDR (e.g. BfArM in Germany, ANSM in France).', source: 'MDR Art. 101', category: 'MDR / IVDR', aliases: ['CA'] },

  // ─── FDA / 21 CFR ──────────────────────────────────────────────
  { term: 'Intended Use', definition: 'The objective intent of the manufacturer regarding the use of a product as reflected in labelling, advertising, and other documentation. This is the FDA/US term (21 CFR 801); the EU/MDR equivalent is "Intended Purpose" (Art. 2(12)). While functionally equivalent, manufacturers must use jurisdiction-specific terminology in their regulatory submissions.', source: 'FDA 21 CFR 801', category: 'FDA / 21 CFR' },
  { term: '510(k)', definition: 'A premarket notification submitted to FDA to demonstrate that a new device is substantially equivalent to a legally marketed predicate device. Most common pathway for Class II devices.', source: 'FDA 21 CFR 807', category: 'FDA / 21 CFR', aliases: ['Premarket Notification', '510k'] },
  { term: 'PMA', definition: 'Premarket Approval — the most stringent FDA device marketing application, required for Class III devices. Requires valid scientific evidence of safety and effectiveness.', source: 'FDA 21 CFR 814', category: 'FDA / 21 CFR', aliases: ['Premarket Approval'] },
  { term: 'De Novo', definition: 'A regulatory pathway for novel low-to-moderate-risk devices that lack a predicate. Allows classification into Class I or II with general and special controls.', source: 'FDA 21 CFR 860', category: 'FDA / 21 CFR', aliases: ['De Novo Classification'] },
  { term: 'Predicate Device', definition: 'A legally marketed device to which the new device is compared in a 510(k) submission to establish substantial equivalence.', source: 'FDA 21 CFR 807.92', category: 'FDA / 21 CFR' },
  { term: 'Substantial Equivalence', definition: 'A determination by FDA that a new device has the same intended use and technological characteristics as a predicate device, or that any differences do not raise new safety/effectiveness questions.', source: 'FDA 21 CFR 807.100', category: 'FDA / 21 CFR', aliases: ['SE'] },
  { term: 'DHF', definition: 'Design History File — a compilation of records describing the design history of a finished device. Contains or references design inputs, outputs, reviews, verification, validation, and transfer records.', source: 'FDA 21 CFR 820.40', category: 'FDA / 21 CFR', aliases: ['Design History File'] },
  { term: 'DMR', definition: 'Device Master Record — a compilation of records containing the procedures and specifications for a finished device. Includes device specifications, production process, QA procedures, packaging, labelling, and installation.', source: 'FDA 21 CFR 820.181', category: 'FDA / 21 CFR', aliases: ['Device Master Record'] },
  { term: 'DHR', definition: 'Device History Record — a compilation of records containing the production history of a finished device, demonstrating that the device was manufactured in accordance with the DMR.', source: 'FDA 21 CFR 820.184', category: 'FDA / 21 CFR', aliases: ['Device History Record'] },
  { term: 'QSR', definition: 'Quality System Regulation — FDA\'s current Good Manufacturing Practice (cGMP) requirements for medical devices (21 CFR Part 820). Being harmonised with ISO 13485 via the QMSR final rule.', source: 'FDA 21 CFR 820', category: 'FDA / 21 CFR', aliases: ['Quality System Regulation'] },
  { term: 'QMSR', definition: 'Quality Management System Regulation — the FDA final rule (effective Feb 2026) that incorporates ISO 13485:2016 by reference, replacing the legacy QSR framework to harmonise with international standards.', source: 'FDA 21 CFR 820 (2026)', category: 'FDA / 21 CFR', aliases: ['Quality Management System Regulation'] },
  { term: 'cGMP', definition: 'Current Good Manufacturing Practice — the minimum requirements for the methods, facilities, and controls used in manufacturing, processing, and packing of a medical device.', source: 'FDA 21 CFR 820', category: 'FDA / 21 CFR', aliases: ['Current Good Manufacturing Practice'] },
  { term: 'MDR (FDA)', definition: 'Medical Device Reporting — the FDA requirement for manufacturers, importers, and device user facilities to report certain device-related adverse events (distinct from EU MDR).', source: 'FDA 21 CFR 803', category: 'FDA / 21 CFR', aliases: ['Medical Device Reporting'] },
  { term: 'Establishment Registration', definition: 'The requirement for owners/operators of establishments that manufacture, distribute, repackage, or relabel medical devices to register annually with FDA.', source: 'FDA 21 CFR 807', category: 'FDA / 21 CFR' },
  { term: 'Device Listing', definition: 'The requirement for manufacturers to list their marketed devices with FDA, including information about the device class, product code, and marketing status.', source: 'FDA 21 CFR 807', category: 'FDA / 21 CFR' },
  { term: 'Product Code', definition: 'A three-letter code assigned by FDA that identifies a generic device category, used for regulatory tracking, classification, and recall identification.', source: 'FDA', category: 'FDA / 21 CFR' },
  { term: 'GMP', definition: 'Good Manufacturing Practice — a set of principles and guidelines for manufacturing that ensures products are consistently produced and controlled according to quality standards.', source: 'FDA 21 CFR 820', category: 'FDA / 21 CFR', aliases: ['Good Manufacturing Practice'] },
  { term: 'IDE', definition: 'Investigational Device Exemption — an FDA approval that allows a device to be used in a clinical study to collect safety and effectiveness data for PMA or 510(k) submission.', source: 'FDA 21 CFR 812', category: 'FDA / 21 CFR', aliases: ['Investigational Device Exemption'] },
  { term: 'Breakthrough Device', definition: 'An FDA program providing more effective treatment/diagnosis of life-threatening or irreversibly debilitating conditions, offering prioritised review and interactive communication.', source: 'FDA', category: 'FDA / 21 CFR', aliases: ['Breakthrough Device Designation'] },
  { term: 'EUA', definition: 'Emergency Use Authorization — an FDA mechanism to authorise unapproved medical products or unapproved uses of approved products during a public health emergency.', source: 'FDA 21 USC 360bbb-3', category: 'FDA / 21 CFR', aliases: ['Emergency Use Authorization'] },
  { term: 'Class I / II / III (FDA)', definition: 'FDA device classification based on risk level. Class I: lowest risk (general controls). Class II: moderate risk (general + special controls). Class III: highest risk (PMA required).', source: 'FDA 21 CFR 860', category: 'FDA / 21 CFR' },
  { term: 'Special Controls', definition: 'Device-specific controls for Class II devices that may include performance standards, post-market surveillance, patient registries, special labelling, or guidance documents.', source: 'FDA 21 CFR 860.24', category: 'FDA / 21 CFR' },
  { term: 'Recall (FDA)', definition: 'A voluntary or mandatory action taken to remove or correct a marketed product that FDA considers in violation of the laws. Classified as Class I, II, or III based on severity.', source: 'FDA 21 CFR 7', category: 'FDA / 21 CFR' },
  { term: 'GUDID', definition: 'Global Unique Device Identification Database — the FDA database that serves as a reference catalogue for every device with a UDI, containing key device identification information.', source: 'FDA', category: 'FDA / 21 CFR', aliases: ['Global Unique Device Identification Database'] },
  { term: 'FD&C Act', definition: 'Federal Food, Drug, and Cosmetic Act — the primary US federal law governing the regulation of food, drugs, medical devices, and cosmetics.', source: 'FDA', category: 'FDA / 21 CFR', aliases: ['Federal Food Drug and Cosmetic Act'] },
  { term: 'Warning Letter', definition: 'An official FDA communication notifying a regulated entity of violations. Considered a significant enforcement action that typically requires a timely written response.', source: 'FDA', category: 'FDA / 21 CFR' },
  { term: 'Form 483', definition: 'An FDA document issued at the end of an inspection listing observed conditions that may constitute violations of the FD&C Act. Not a final determination of violation.', source: 'FDA', category: 'FDA / 21 CFR', aliases: ['FDA 483'] },
  { term: 'MAUDE', definition: 'Manufacturer and User Facility Device Experience — the FDA database of mandatory and voluntary reports of adverse events involving medical devices.', source: 'FDA', category: 'FDA / 21 CFR', aliases: ['Manufacturer and User Facility Device Experience'] },
  { term: 'Premarket Submission', definition: 'Any submission to FDA seeking clearance, approval, or authorisation to market a medical device (510(k), PMA, De Novo, EUA, HDE).', source: 'FDA', category: 'FDA / 21 CFR' },
  { term: 'HDE', definition: 'Humanitarian Device Exemption — a marketing pathway for devices intended to benefit patients with rare diseases or conditions (affecting fewer than 8,000 individuals per year in the US).', source: 'FDA 21 CFR 814 Subpart H', category: 'FDA / 21 CFR', aliases: ['Humanitarian Device Exemption'] },

  // ─── ISO 13485 / QMS ───────────────────────────────────────────
  { term: 'QMS', definition: 'Quality Management System — a formalised system documenting processes, procedures, and responsibilities for achieving quality policies and objectives. ISO 13485 specifies QMS requirements for medical devices.', source: 'ISO 13485', category: 'ISO 13485 / QMS', aliases: ['Quality Management System'] },
  { term: 'Management Review', definition: 'A periodic review by top management of the QMS to ensure its continuing suitability, adequacy, and effectiveness. Includes review of audit results, complaints, CAPAs, and process performance.', source: 'ISO 13485 §5.6', category: 'ISO 13485 / QMS' },
  { term: 'Design Input', definition: 'The physical and performance requirements of a device that are used as a basis for device design. Must address intended use, performance, safety, regulatory requirements, and applicable standards.', source: 'ISO 13485 §7.3.3', category: 'ISO 13485 / QMS' },
  { term: 'Design Output', definition: 'The results of the design process at each design phase and at the end. Must meet design input requirements, provide information for purchasing, production, and servicing, and specify acceptance criteria.', source: 'ISO 13485 §7.3.4', category: 'ISO 13485 / QMS' },
  { term: 'Design Verification', definition: 'Confirmation through examination and provision of objective evidence that design outputs meet design input requirements. Tests, inspections, analyses, or demonstrations.', source: 'ISO 13485 §7.3.5', category: 'ISO 13485 / QMS', aliases: ['Verification'] },
  { term: 'Design Validation', definition: 'Confirmation through examination and provision of objective evidence that the device conforms to defined user needs and intended uses. Performed on representative production units under defined operating conditions.', source: 'ISO 13485 §7.3.6', category: 'ISO 13485 / QMS', aliases: ['Validation'] },
  { term: 'Design Transfer', definition: 'The process of translating the final device design into production specifications, ensuring the design can be manufactured consistently and reliably.', source: 'ISO 13485 §7.3.8', category: 'ISO 13485 / QMS' },
  { term: 'Design Review', definition: 'A systematic examination of a design at suitable stages to evaluate design results, identify problems, and propose necessary actions. Must include representatives of functions concerned.', source: 'ISO 13485 §7.3.5', category: 'ISO 13485 / QMS' },
  { term: 'Nonconformity', definition: 'Non-fulfilment of a specified requirement. May relate to product, process, or QMS. Requires investigation, disposition, and potentially CAPA.', source: 'ISO 13485 §8.3', category: 'ISO 13485 / QMS', aliases: ['NC', 'Nonconforming Product'] },
  { term: 'CAPA', definition: 'Corrective Action and Preventive Action — a systematic approach to investigating, understanding, and correcting discrepancies while attempting to prevent their recurrence (corrective) or occurrence (preventive).', source: 'ISO 13485 §8.5', category: 'ISO 13485 / QMS', aliases: ['Corrective and Preventive Action'] },
  { term: 'Document Control', definition: 'The process of managing documents within the QMS, including approval, review, updating, identification of changes, availability, legibility, and control of external documents.', source: 'ISO 13485 §4.2.4', category: 'ISO 13485 / QMS' },
  { term: 'Record Control', definition: 'The process of establishing and maintaining records to provide evidence of conformity to requirements and effective operation of the QMS. Records must remain legible, identifiable, and retrievable.', source: 'ISO 13485 §4.2.5', category: 'ISO 13485 / QMS' },
  { term: 'Internal Audit', definition: 'A systematic, independent, and documented process for obtaining evidence and evaluating it objectively to determine the extent to which QMS requirements are fulfilled.', source: 'ISO 13485 §8.2.4', category: 'ISO 13485 / QMS' },
  { term: 'Process Validation', definition: 'Establishing by objective evidence that a process consistently produces a result or product meeting predetermined specifications. Required for any process where output cannot be fully verified.', source: 'ISO 13485 §7.5.6', category: 'ISO 13485 / QMS' },
  { term: 'Purchasing Controls', definition: 'Processes to ensure purchased products conform to specified requirements, including supplier evaluation, selection criteria, and verification of purchased product.', source: 'ISO 13485 §7.4', category: 'ISO 13485 / QMS' },
  { term: 'Management Representative', definition: 'A member of management appointed by top management with responsibility and authority for ensuring QMS processes are established and maintained, reporting on QMS performance, and promoting regulatory awareness.', source: 'ISO 13485 §5.5.2', category: 'ISO 13485 / QMS' },
  { term: 'Traceability', definition: 'The ability to trace the history, application, or location of an item or activity by means of recorded identification. For medical devices, includes raw materials through distribution.', source: 'ISO 13485 §7.5.9', category: 'ISO 13485 / QMS' },
  { term: 'Customer Complaint', definition: 'Any written, electronic, or oral communication that alleges deficiencies related to identity, quality, durability, reliability, usability, safety, or performance of a device.', source: 'ISO 13485 §8.2.2', category: 'ISO 13485 / QMS', aliases: ['Complaint'] },
  { term: 'Risk-Based Approach', definition: 'A principle in ISO 13485:2016 requiring organisations to apply risk management throughout QMS processes, proportionate to the risk associated with the medical device.', source: 'ISO 13485 §0.2', category: 'ISO 13485 / QMS' },
  { term: 'Advisory Notice', definition: 'A notice issued by the manufacturer for supplementary information and/or advice on the action to be taken regarding the use of a medical device after it has been placed on the market.', source: 'ISO 13485', category: 'ISO 13485 / QMS' },
  { term: 'Product Realization', definition: 'The sequence of processes and sub-processes required to achieve the creation of a product. Covers planning, customer requirements, design, purchasing, production, and monitoring.', source: 'ISO 13485 §7', category: 'ISO 13485 / QMS' },
  { term: 'Supplier Qualification', definition: 'The process of evaluating and approving suppliers based on their ability to supply products or services in accordance with specified requirements. Includes initial assessment and ongoing monitoring.', source: 'ISO 13485 §7.4.1', category: 'ISO 13485 / QMS' },
  { term: 'Infrastructure', definition: 'The system of facilities, equipment, and supporting services needed to achieve conformity to product requirements. Includes buildings, workspace, process equipment, and IT systems.', source: 'ISO 13485 §6.3', category: 'ISO 13485 / QMS' },

  // ─── ISO 14971 / Risk Management ──────────────────────────────
  { term: 'Hazard', definition: 'A potential source of harm. In risk management, hazards are systematically identified and analysed for all reasonably foreseeable sequences of events that could lead to hazardous situations.', source: 'ISO 14971 §3.4', category: 'ISO 14971 / Risk Management' },
  { term: 'Hazardous Situation', definition: 'A circumstance in which people, property, or the environment are exposed to one or more hazards. May arise from device use, failure, or environmental conditions.', source: 'ISO 14971 §3.5', category: 'ISO 14971 / Risk Management' },
  { term: 'Harm', definition: 'Physical injury or damage to the health of people, or damage to property or the environment. The ultimate undesired consequence of a hazardous situation.', source: 'ISO 14971 §3.3', category: 'ISO 14971 / Risk Management' },
  { term: 'Severity', definition: 'A measure of the possible consequences of a hazard. Typically categorised from negligible to catastrophic. One of the two components of risk estimation.', source: 'ISO 14971 §3.19', category: 'ISO 14971 / Risk Management' },
  { term: 'Probability of Occurrence', definition: 'The likelihood that a hazardous situation will occur, estimated from available data, models, or expert judgment. One of the two components of risk estimation.', source: 'ISO 14971 §3.15', category: 'ISO 14971 / Risk Management' },
  { term: 'Risk', definition: 'The combination of the probability of occurrence of harm and the severity of that harm. Risk is analysed, evaluated, controlled, and monitored throughout the device lifecycle.', source: 'ISO 14971 §3.16', category: 'ISO 14971 / Risk Management' },
  { term: 'Risk Analysis', definition: 'The systematic use of available information to identify hazards and to estimate the risk. Includes intended use, identification of hazards, estimation of risks, and risk evaluation.', source: 'ISO 14971 §5', category: 'ISO 14971 / Risk Management' },
  { term: 'Risk Evaluation', definition: 'The process of comparing the estimated risk against given risk criteria to determine the acceptability of the risk. Uses manufacturer-defined risk acceptability criteria.', source: 'ISO 14971 §6', category: 'ISO 14971 / Risk Management' },
  { term: 'Risk Control', definition: 'The process of decision-making and implementation of measures to reduce or maintain risk within specified levels. Follows a priority order: inherent safety by design, protective measures, information for safety.', source: 'ISO 14971 §7', category: 'ISO 14971 / Risk Management' },
  { term: 'Residual Risk', definition: 'The risk remaining after risk control measures have been implemented. Must be evaluated against the manufacturer\'s criteria for risk acceptability and the overall risk-benefit analysis.', source: 'ISO 14971 §3.17', category: 'ISO 14971 / Risk Management' },
  { term: 'Risk-Benefit Analysis', definition: 'An analysis of all residual risks and their benefits to determine whether the medical benefits outweigh the residual risks. Required when residual risk exceeds acceptability criteria.', source: 'ISO 14971 §7.4', category: 'ISO 14971 / Risk Management' },
  { term: 'ALARP', definition: 'As Low As Reasonably Practicable — a principle stating that residual risks should be reduced as far as reasonably practicable, considering the state of the art, cost, and the nature and extent of the risk.', source: 'ISO 14971', category: 'ISO 14971 / Risk Management', aliases: ['As Low As Reasonably Practicable'] },
  { term: 'Risk Management File', definition: 'A set of records and other documents produced by risk management, providing traceability for each identified hazard through risk analysis, evaluation, control, and residual risk assessment.', source: 'ISO 14971 §3.18', category: 'ISO 14971 / Risk Management', aliases: ['RMF'] },
  { term: 'Risk Management Plan', definition: 'A document that specifies the scope, roles, risk acceptability criteria, verification activities, production and post-production activities, and review timing for risk management.', source: 'ISO 14971 §4.4', category: 'ISO 14971 / Risk Management' },
  { term: 'Risk Management Report', definition: 'A document providing a review of the risk management process for a particular device, summarising all identified hazards, risk controls, residual risks, and overall risk acceptability conclusions.', source: 'ISO 14971 §8', category: 'ISO 14971 / Risk Management' },
  { term: 'FMEA', definition: 'Failure Mode and Effects Analysis — a systematic technique for identifying potential failure modes, their causes, effects, and the severity/frequency/detectability of each. Used as a risk analysis tool.', source: 'ISO 14971 / IEC 60812', category: 'ISO 14971 / Risk Management', aliases: ['Failure Mode and Effects Analysis'] },
  { term: 'FTA', definition: 'Fault Tree Analysis — a top-down, deductive analytical method used to determine the root causes of an identified undesired event (top event) by tracing logical combinations of faults.', source: 'ISO 14971 / IEC 61025', category: 'ISO 14971 / Risk Management', aliases: ['Fault Tree Analysis'] },
  { term: 'State of the Art', definition: 'The developed stage of technical capability at a given time as regards products, processes, and services, based on the relevant consolidated findings of science, technology, and experience.', source: 'ISO 14971 §3.20', category: 'ISO 14971 / Risk Management', aliases: ['SOTA'] },
  { term: 'Foreseeable Misuse', definition: 'Use of a product or system in a way not intended by the manufacturer but which can result from readily predictable human behaviour. Must be considered in risk analysis.', source: 'ISO 14971 §5.4', category: 'ISO 14971 / Risk Management' },
  { term: 'Benefit', definition: 'A positive impact or desirable outcome of the use of a medical device on the health of an individual, or a positive impact on patient management or public health.', source: 'ISO 14971 §3.2', category: 'ISO 14971 / Risk Management' },

  // ─── IEC 62304 / Software ─────────────────────────────────────
  { term: 'Software Item', definition: 'Any identifiable part of a computer program. A software item may be a software system, software subsystem, or a software unit. A hierarchical decomposition element.', source: 'IEC 62304 §3.31', category: 'IEC 62304 / Software' },
  { term: 'Software Unit', definition: 'A software item that is not subdivided into other items. The lowest level of the software decomposition, subject to unit testing and code review.', source: 'IEC 62304 §3.36', category: 'IEC 62304 / Software' },
  { term: 'Software System', definition: 'An integrated collection of software items organised to accomplish a specific function or set of functions. The highest level of the software architecture.', source: 'IEC 62304 §3.35', category: 'IEC 62304 / Software' },
  { term: 'SOUP', definition: 'Software of Unknown Provenance — a software item that is already developed and generally available but not developed for the purpose of being incorporated into the medical device (e.g. open-source libraries, commercial off-the-shelf software).', source: 'IEC 62304 §3.29', category: 'IEC 62304 / Software', aliases: ['Software of Unknown Provenance', 'OTS', 'COTS', 'Off-The-Shelf Software'] },
  { term: 'Software Safety Classification', definition: 'Classification of software systems/items into Class A (no injury or damage possible), Class B (non-serious injury possible), or Class C (death or serious injury possible) based on risk contribution.', source: 'IEC 62304 §4.3', category: 'IEC 62304 / Software' },
  { term: 'Software Development Plan', definition: 'A document specifying the activities, deliverables, resources, and schedule for software development including standards, methods, tools, and programming languages to be used.', source: 'IEC 62304 §5.1', category: 'IEC 62304 / Software' },
  { term: 'Software Requirements Specification', definition: 'A document that specifies the requirements for a software system/item including functional, performance, interface, design, and implementation requirements.', source: 'IEC 62304 §5.2', category: 'IEC 62304 / Software', aliases: ['SRS'] },
  { term: 'Software Architecture', definition: 'The organisational structure of a software system including components, their interfaces, and the principles governing their design and evolution.', source: 'IEC 62304 §5.3', category: 'IEC 62304 / Software' },
  { term: 'Software Problem Report', definition: 'A record of actual or potential behaviour of a software product that a user or other interested person believes to be unsafe, inappropriate, or in contradiction with specifications.', source: 'IEC 62304 §9', category: 'IEC 62304 / Software', aliases: ['SPR'] },
  { term: 'Software Change Request', definition: 'A documented request for a modification to a software product, including the reason for the change and its urgency. Subject to change control processes.', source: 'IEC 62304 §6.2', category: 'IEC 62304 / Software' },
  { term: 'Software Maintenance', definition: 'The modification of a software product after delivery to correct faults, improve performance, or adapt to a changed environment.', source: 'IEC 62304 §6', category: 'IEC 62304 / Software' },
  { term: 'Software Configuration Management', definition: 'A discipline applying technical and administrative direction and surveillance to identify and document the functional and physical characteristics of a software item, control changes, and record and report change processing.', source: 'IEC 62304 §8', category: 'IEC 62304 / Software', aliases: ['SCM'] },
  { term: 'Anomaly', definition: 'Any condition that deviates from expectations based on requirements specifications, design documents, user documents, standards, etc., or from someone\'s perceptions or experiences.', source: 'IEC 62304 §3.2', category: 'IEC 62304 / Software' },
  { term: 'Integration Testing', definition: 'Testing performed to expose defects in the interfaces and interactions between integrated software items or between software and hardware.', source: 'IEC 62304 §5.6', category: 'IEC 62304 / Software' },
  { term: 'Regression Testing', definition: 'Selective retesting of a system or component to verify that modifications have not caused unintended effects and that the system still complies with its specified requirements.', source: 'IEC 62304', category: 'IEC 62304 / Software' },
  { term: 'Software Bill of Materials', definition: 'A formal, machine-readable inventory of software components and dependencies, their relationships, and supply chain information. Increasingly required for cybersecurity transparency.', source: 'IEC 62304 / FDA', category: 'IEC 62304 / Software', aliases: ['SBOM'] },
  { term: 'Cybersecurity', definition: 'The process of preventing unauthorised access, modification, misuse, or denial of use, or the unauthorised use of information that is stored, accessed, or transferred from a medical device.', source: 'IEC 62304 / FDA', category: 'IEC 62304 / Software' },
  { term: 'SaMD', definition: 'Software as a Medical Device — software intended to be used for one or more medical purposes that performs these purposes without being part of a hardware medical device.', source: 'IMDRF / MDR', category: 'IEC 62304 / Software', aliases: ['Software as a Medical Device'] },
  { term: 'SiMD', definition: 'Software in a Medical Device — software that is integral to a medical device and is necessary for the device to achieve its intended purpose. Not standalone.', source: 'IMDRF / MDR', category: 'IEC 62304 / Software', aliases: ['Software in a Medical Device'] },

  // ─── IEC 62366 / Usability ────────────────────────────────────
  { term: 'Use Specification', definition: 'A specification of the intended medical indication, intended patient population, intended part of the body, intended user profile, use environment, and operating principle of the device.', source: 'IEC 62366-1 §5.1', category: 'IEC 62366 / Usability' },
  { term: 'User Interface', definition: 'The means by which the user and the medical device interact. Includes all components, hardware and software, that the user interacts with to operate the device.', source: 'IEC 62366-1 §3.27', category: 'IEC 62366 / Usability', aliases: ['UI'] },
  { term: 'Use Error', definition: 'A user action or lack of action while using the medical device that leads to a different result than intended by the manufacturer or expected by the user.', source: 'IEC 62366-1 §3.21', category: 'IEC 62366 / Usability' },
  { term: 'Formative Evaluation', definition: 'A usability evaluation conducted during the design process to identify usability problems and improve the user interface. Iterative and may include expert reviews, cognitive walkthroughs, and user testing.', source: 'IEC 62366-1 §5.7', category: 'IEC 62366 / Usability' },
  { term: 'Summative Evaluation', definition: 'A usability evaluation conducted to obtain objective evidence that the user interface can be used safely and effectively. Typically the final validation step using simulated use or actual use.', source: 'IEC 62366-1 §5.9', category: 'IEC 62366 / Usability' },
  { term: 'Hazard-Related Use Scenario', definition: 'A use scenario whose outcome is a hazardous situation. Identified through risk analysis and used to design evaluation tasks in summative usability testing.', source: 'IEC 62366-1 §5.4', category: 'IEC 62366 / Usability' },
  { term: 'User Profile', definition: 'A description of the intended users including demographic characteristics, education, training, knowledge, physical abilities, and cultural/linguistic background.', source: 'IEC 62366-1 §5.1', category: 'IEC 62366 / Usability' },
  { term: 'Use Environment', definition: 'The physical and social surroundings in which the medical device is used, including lighting, noise, distractions, temperature, and hygiene conditions.', source: 'IEC 62366-1 §5.1', category: 'IEC 62366 / Usability' },
  { term: 'Usability Engineering File', definition: 'The set of records and documents produced during the usability engineering process, providing evidence of conformance with IEC 62366-1 requirements.', source: 'IEC 62366-1 §4.2', category: 'IEC 62366 / Usability', aliases: ['UEF'] },
  { term: 'Task Analysis', definition: 'A systematic examination of a user\'s tasks to identify the step-by-step actions required to accomplish specific tasks with the medical device, including potential errors.', source: 'IEC 62366-1 §5.5', category: 'IEC 62366 / Usability' },
  { term: 'Cognitive Walkthrough', definition: 'A usability inspection method in which evaluators step through a task scenario and assess the learnability and discoverability of the user interface at each step.', source: 'IEC 62366-1', category: 'IEC 62366 / Usability' },
  { term: 'Simulated Use', definition: 'A type of usability testing where users perform tasks under simulated conditions that replicate the essential aspects of real use without actual clinical use of the device.', source: 'IEC 62366-1', category: 'IEC 62366 / Usability' },
  { term: 'Actual Use', definition: 'The real-world use of a medical device by intended users in the intended use environment. Actual use data may be used for summative evaluation when simulated use is insufficient.', source: 'IEC 62366-1', category: 'IEC 62366 / Usability' },
  { term: 'Human Factors Engineering', definition: 'The application of knowledge about human capabilities, limitations, and behaviour to the design of tools, devices, systems, and environments for safe and effective human use.', source: 'IEC 62366 / FDA HFE Guidance', category: 'IEC 62366 / Usability', aliases: ['HFE'] },
  { term: 'Instructions for Use', definition: 'Information provided by the manufacturer to convey to the user the purpose and proper use of a device, including precautions, warnings, and contraindications.', source: 'IEC 62366-1 / MDR', category: 'IEC 62366 / Usability', aliases: ['IFU'] },

  // ─── EHDS / PPWR / Sustainability ─────────────────────────────
  { term: 'EHDS', definition: 'European Health Data Space — EU regulation (2025/327) establishing a framework for the use of electronic health data for primary care delivery and secondary use (research, policy, innovation).', source: 'EU 2025/327', category: 'EHDS / PPWR / Sustainability', aliases: ['European Health Data Space'] },
  { term: 'Data Holder', definition: 'A natural or legal person, public authority, or agency that has the right or obligation to make electronic health data available for secondary use under EHDS.', source: 'EHDS Art. 2', category: 'EHDS / PPWR / Sustainability' },
  { term: 'Health Data Access Body', definition: 'A national body designated by Member States to manage access to electronic health data for secondary use. Evaluates data permit applications and ensures compliance.', source: 'EHDS Art. 36', category: 'EHDS / PPWR / Sustainability', aliases: ['HDAB'] },
  { term: 'EEHRxF', definition: 'European Electronic Health Record Exchange Format — a standardised format for cross-border exchange of electronic health records, ensuring interoperability across EU Member States.', source: 'EHDS Art. 6', category: 'EHDS / PPWR / Sustainability', aliases: ['European Electronic Health Record Exchange Format'] },
  { term: 'HealthDCAT-AP', definition: 'Health Data Catalogue Application Profile — a metadata standard for describing health datasets to facilitate their discoverability and access for secondary use under EHDS.', source: 'EHDS', category: 'EHDS / PPWR / Sustainability' },
  { term: 'Secondary Use', definition: 'The processing of electronic health data for purposes other than the original clinical care, such as research, innovation, policy-making, regulatory activities, and pharmacovigilance.', source: 'EHDS Chapter IV', category: 'EHDS / PPWR / Sustainability' },
  { term: 'Primary Use', definition: 'The processing of electronic health data for the provision of healthcare services, including diagnosis, treatment, and patient management.', source: 'EHDS Chapter II', category: 'EHDS / PPWR / Sustainability' },
  { term: 'Data Permit', definition: 'An authorisation issued by a Health Data Access Body granting access to specific electronic health data for a defined secondary use purpose under strict conditions.', source: 'EHDS Art. 46', category: 'EHDS / PPWR / Sustainability' },
  { term: 'PPWR', definition: 'Packaging and Packaging Waste Regulation (EU) 2025/40 — the EU regulation replacing Directive 94/62/EC, establishing requirements for packaging sustainability, recyclability, recycled content, labelling, and extended producer responsibility.', source: 'EU 2025/40', category: 'EHDS / PPWR / Sustainability', aliases: ['Packaging and Packaging Waste Regulation'] },
  { term: 'EPR', definition: 'Extended Producer Responsibility — an environmental policy approach requiring producers (including medical device manufacturers) to take responsibility for the entire lifecycle of their packaging, including collection, recycling, and disposal.', source: 'PPWR Art. 40', category: 'EHDS / PPWR / Sustainability', aliases: ['Extended Producer Responsibility'] },
  { term: 'PFAS', definition: 'Per- and Polyfluoroalkyl Substances — a group of synthetic chemicals ("forever chemicals") subject to restrictions under PPWR for food-contact and other packaging. Manufacturers must verify absence in packaging materials.', source: 'PPWR Art. 5', category: 'EHDS / PPWR / Sustainability', aliases: ['Per- and Polyfluoroalkyl Substances', 'Forever Chemicals'] },
  { term: 'Design for Recycling', definition: 'A product design principle requiring that packaging be designed to be recyclable at scale, using mono-materials or compatible combinations, and avoiding substances that hinder recycling.', source: 'PPWR Art. 6', category: 'EHDS / PPWR / Sustainability', aliases: ['DfR'] },
  { term: 'Digital Product Passport', definition: 'A structured digital dataset linked to a product providing information about its composition, sustainability, circularity, origin, and end-of-life management. Part of the EU Green Deal strategy.', source: 'PPWR / ESPR', category: 'EHDS / PPWR / Sustainability', aliases: ['DPP'] },
  { term: 'Carbon Footprint', definition: 'The total greenhouse gas emissions caused directly and indirectly by a product throughout its lifecycle. Increasingly required for regulatory reporting and sustainability compliance.', source: 'PPWR / ESPR', category: 'EHDS / PPWR / Sustainability' },
  { term: 'Circular Economy', definition: 'An economic system aimed at eliminating waste and the continual use of resources through designing for durability, reuse, refurbishment, remanufacturing, and recycling.', source: 'EU Green Deal', category: 'EHDS / PPWR / Sustainability' },

  // ─── MDCG Guidance Documents ────────────────────────────────────
  { term: 'MDCG 2019-11 rev.1', definition: 'Guidance on qualification and classification of software — provides criteria for determining whether standalone software qualifies as a medical device and its risk classification under MDR Annex VIII rules.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Software Classification Guidance'] },
  { term: 'MDCG 2020-1 rev.1', definition: 'Guidance on clinical evaluation (MDR) / performance evaluation (IVDR) of medical device software — covers methodologies for demonstrating clinical evidence for SaMD/SiMD.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Software Clinical Evaluation'] },
  { term: 'MDCG 2020-5', definition: 'Guidance on clinical evaluation — equivalence — describes requirements and methodology for demonstrating equivalence to another device for leveraging existing clinical data.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Equivalence Guidance'] },
  { term: 'MDCG 2020-6', definition: 'Guidance on sufficient clinical evidence for legacy devices — addresses clinical evidence expectations during transition from MDD to MDR for legacy devices.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Legacy Device Clinical Evidence'] },
  { term: 'MDCG 2020-13', definition: 'Guidance on clinical evaluation assessment report (CEAR) template — provides the Notified Body template for documenting clinical evaluation assessments of Class III and implantable devices.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['CEAR Template'] },
  { term: 'MDCG 2020-16', definition: 'Guidance on classification of medical devices regarding reprocessing — clarifies classification rules for single-use devices that are reprocessed under MDR Art. 17.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Reprocessing Classification'] },
  { term: 'MDCG 2021-6', definition: 'Regulation (EU) 2017/745 — questions and answers regarding clinical investigation — provides clarifications on requirements for clinical investigations under MDR.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Clinical Investigation Q&A'] },
  { term: 'MDCG 2021-24', definition: 'Guidance on cybersecurity for medical devices — covers cybersecurity requirements throughout the device lifecycle including pre-market and post-market considerations.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Cybersecurity Guidance'] },
  { term: 'MDCG 2022-4', definition: 'Guidance on PMCF plan and PMCF evaluation report templates — provides templates for Post-Market Clinical Follow-up plans and evaluation reports required by MDR.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['PMCF Templates'] },
  { term: 'MDCG 2022-14', definition: 'Guidance on significant changes regarding the transitional provision under Article 120 of the MDR — defines what constitutes a "significant change" that would invalidate legacy certificates.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Significant Changes Guidance'] },
  { term: 'MDCG 2021-5', definition: 'Guidance on standardisation for medical devices — clarifies the role of harmonised standards and common specifications in demonstrating conformity with MDR/IVDR.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Standardisation Guidance'] },
  { term: 'MDCG 2019-9 rev.1', definition: 'Summary of safety and clinical performance — a template and guidance for manufacturers to prepare the publicly available SSCP required for Class III and implantable devices.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['SSCP Guidance'] },
  { term: 'MDCG 2019-16 rev.1', definition: 'Guidance on cybersecurity for medical devices — provides recommendations for manufacturers on how to fulfil cybersecurity requirements, including threat modelling and vulnerability management.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Cybersecurity Recommendations'] },
  { term: 'MDCG 2020-3', definition: 'Guidance on significant changes to QMS — covers Notified Body assessment of quality management system changes, including criteria for requiring re-audit.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['QMS Changes Guidance'] },
  { term: 'MDCG 2021-1', definition: 'Guidance on harmonised administrative practices and alternative technical solutions during transition — addresses practical implementation challenges of MDR transition.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Transition Guidance'] },
  { term: 'MDCG 2022-18', definition: 'Guidance on the Unique Device Identification system under Regulation (EU) 2017/745 and (EU) 2017/746 — covers UDI assignment, registration, and EUDAMED requirements.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['UDI Guidance'] },
  { term: 'MDCG 2023-1', definition: 'Guidance on the health institution exemption under Article 5(5) MDR and Article 5(5) IVDR — defines when health institutions may manufacture devices in-house without full MDR compliance.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Health Institution Exemption'] },
  { term: 'MDCG 2024-1', definition: 'Guidance on the classification of medical devices with a substance component — addresses classification rules for drug-device combinations under MDR.', source: 'MDCG', category: 'MDCG Guidance', aliases: ['Drug-Device Classification'] },

  // ─── MDR / IVDR Key Annexes ────────────────────────────────────
  { term: 'MDR Annex I — GSPRs', definition: 'General Safety and Performance Requirements — the fundamental requirements all medical devices must satisfy. Covers general requirements (Ch. I), design & manufacturing (Ch. II), and information requirements (Ch. III) including labelling and IFU.', source: 'MDR Annex I', category: 'MDCG Guidance', aliases: ['GSPRs', 'Annex I'] },
  { term: 'MDR Annex II — Technical Documentation', definition: 'Specifies the structure and content of technical documentation including device description, design & manufacturing information, GSPRs, risk-benefit analysis, product verification & validation, and clinical evaluation.', source: 'MDR Annex II', category: 'MDCG Guidance', aliases: ['Technical Documentation Structure'] },
  { term: 'MDR Annex III — Post-Market Surveillance', definition: 'Specifies requirements for the post-market surveillance system documentation, including PMS plan, PMS reports, and PSURs.', source: 'MDR Annex III', category: 'MDCG Guidance', aliases: ['PMS Documentation'] },
  { term: 'MDR Annex XIV — Clinical Evaluation', definition: 'Part A: Clinical evaluation procedure and documentation. Part B: Post-market clinical follow-up. Defines the methodology for systematic clinical data assessment.', source: 'MDR Annex XIV', category: 'MDCG Guidance', aliases: ['Clinical Evaluation Annex'] },
  { term: 'MDR Annex XV — Clinical Investigations', definition: 'Requirements for clinical investigations including application, conduct, reporting, and ethics. Covers informed consent, clinical investigation plan, and adverse event reporting.', source: 'MDR Annex XV', category: 'MDCG Guidance', aliases: ['Clinical Investigation Annex'] },
  { term: 'MDR Annex VIII — Classification Rules', definition: 'Contains 22 classification rules for medical devices based on intended purpose, duration of use, invasiveness, active vs non-active, and specific technology criteria. Determines Class I, IIa, IIb, or III.', source: 'MDR Annex VIII', category: 'MDCG Guidance', aliases: ['Classification Rules Annex'] },
  { term: 'IVDR Annex I — GSPRs', definition: 'General Safety and Performance Requirements specific to in vitro diagnostic medical devices. Includes requirements for analytical and clinical performance, stability, and metrological traceability.', source: 'IVDR Annex I', category: 'MDCG Guidance', aliases: ['IVDR GSPRs'] },

  // ─── Harmonised Standards ──────────────────────────────────────
  { term: 'EN ISO 13485:2016', definition: 'Quality management systems — requirements for regulatory purposes. The harmonised standard for medical device QMS, providing presumption of conformity with MDR quality system requirements.', source: 'ISO 13485:2016', category: 'Harmonised Standards', aliases: ['ISO 13485'] },
  { term: 'EN ISO 14971:2019+A11:2021', definition: 'Application of risk management to medical devices. The harmonised standard for systematic identification, evaluation, control, and monitoring of risks throughout the device lifecycle.', source: 'ISO 14971:2019', category: 'Harmonised Standards', aliases: ['ISO 14971'] },
  { term: 'EN IEC 62304:2006+A1:2015', definition: 'Medical device software — software lifecycle processes. Defines requirements for development, maintenance, risk management, configuration management, and problem resolution of medical device software.', source: 'IEC 62304:2006+A1', category: 'Harmonised Standards', aliases: ['IEC 62304'] },
  { term: 'EN IEC 62366-1:2015+A1:2020', definition: 'Medical devices — application of usability engineering to medical devices. Specifies the process for analysing, specifying, developing, and evaluating the usability of a medical device.', source: 'IEC 62366-1:2015+A1', category: 'Harmonised Standards', aliases: ['IEC 62366-1'] },
  { term: 'EN ISO 10993-1:2020', definition: 'Biological evaluation of medical devices — Part 1: Evaluation and testing within a risk management process. Framework standard for biocompatibility evaluation using a risk-based approach.', source: 'ISO 10993-1:2020', category: 'Harmonised Standards', aliases: ['ISO 10993-1', 'Biocompatibility'] },
  { term: 'EN ISO 11135:2014', definition: 'Sterilization of health-care products — Ethylene oxide — Requirements for development, validation, and routine control of a sterilization process for medical devices.', source: 'ISO 11135:2014', category: 'Harmonised Standards', aliases: ['ISO 11135', 'EtO Sterilization'] },
  { term: 'EN ISO 11137-1:2015', definition: 'Sterilization of health care products — Radiation — Part 1: Requirements for development, validation and routine control of a sterilization process for medical devices.', source: 'ISO 11137-1:2015', category: 'Harmonised Standards', aliases: ['ISO 11137', 'Radiation Sterilization'] },
  { term: 'EN ISO 11607-1:2019', definition: 'Packaging for terminally sterilized medical devices — Part 1: Requirements for materials, sterile barrier systems, and packaging systems.', source: 'ISO 11607-1:2019', category: 'Harmonised Standards', aliases: ['ISO 11607', 'Sterile Packaging'] },
  { term: 'EN IEC 60601-1:2006+A1:2013', definition: 'Medical electrical equipment — Part 1: General requirements for basic safety and essential performance. The foundational safety standard for all medical electrical equipment.', source: 'IEC 60601-1', category: 'Harmonised Standards', aliases: ['IEC 60601-1', 'Electrical Safety'] },
  { term: 'EN 62366-1:2015/A2:2024', definition: 'Amendment 2 to usability engineering standard — incorporates updated requirements for usability validation and formative evaluation methods aligned with current regulatory expectations.', source: 'IEC 62366-1 A2:2024', category: 'Harmonised Standards', aliases: ['IEC 62366-1 A2'] },
  { term: 'EN ISO 15223-1:2021', definition: 'Medical devices — symbols to be used with information to be supplied by the manufacturer — Part 1: General requirements. Defines standardised symbols for medical device labelling.', source: 'ISO 15223-1:2021', category: 'Harmonised Standards', aliases: ['ISO 15223-1', 'Label Symbols'] },
  { term: 'EN ISO 20417:2021', definition: 'Medical devices — information to be supplied by the manufacturer. Specifies requirements for information supplied with medical devices including labelling, IFU, and packaging.', source: 'ISO 20417:2021', category: 'Harmonised Standards', aliases: ['ISO 20417', 'Device Information'] },

  // ─── General Regulatory ────────────────────────────────────────
  { term: 'CE Marking', definition: 'Conformité Européenne — a marking affixed to products indicating conformity with applicable EU legislation. For medical devices, CE marking demonstrates compliance with MDR/IVDR requirements.', source: 'MDR Art. 20', category: 'General Regulatory', aliases: ['CE Mark', 'Conformité Européenne'] },
  { term: 'Labelling', definition: 'Any written, printed, or graphic matter on the medical device itself, its packaging, or accompanying documents. Must meet specific requirements of MDR Annex I Chapter III.', source: 'MDR Annex I Ch. III', category: 'General Regulatory' },
  { term: 'IFU', definition: 'Instructions for Use — information provided by the manufacturer to inform the user of the device\'s intended purpose, proper use, precautions, contraindications, and other relevant information.', source: 'MDR Annex I §23', category: 'General Regulatory', aliases: ['Instructions for Use'] },
  { term: 'Biocompatibility', definition: 'The ability of a material to perform with an appropriate host response in a specific situation. Evaluated according to ISO 10993 series for materials in contact with the body.', source: 'ISO 10993-1', category: 'General Regulatory' },
  { term: 'Sterilisation', definition: 'A validated process used to render a product free from viable micro-organisms. Common methods include EtO, gamma irradiation, steam, and hydrogen peroxide plasma.', source: 'ISO 11135 / ISO 11137', category: 'General Regulatory', aliases: ['Sterilization'] },
  { term: 'Shelf Life', definition: 'The period of time during which a medical device remains suitable for its intended use when stored under specified conditions. Determined through accelerated and real-time ageing studies.', source: 'ISO 11607', category: 'General Regulatory' },
  { term: 'Packaging Validation', definition: 'Testing to confirm that the sterile barrier system and packaging maintain device sterility and integrity through manufacturing, sterilisation, storage, transport, and distribution.', source: 'ISO 11607', category: 'General Regulatory' },
  { term: 'Clinical Data', definition: 'Safety and/or performance information generated from the clinical use of a device, including results from clinical investigations, published literature, clinical experience, and PMS data.', source: 'MDR Art. 2(48)', category: 'General Regulatory' },
  { term: 'Predicate', definition: 'A legally marketed device used as a comparison reference point for demonstrating substantial equivalence (FDA) or equivalence analysis (MDR Clinical Evaluation).', source: 'FDA / MDR', category: 'General Regulatory' },
  { term: 'Equivalence', definition: 'The assessment that a device under evaluation is sufficiently similar to another device (clinical, technical, and biological characteristics) to leverage existing clinical data.', source: 'MDR Annex XIV Part A §3', category: 'General Regulatory' },
  { term: 'MDSAP', definition: 'Medical Device Single Audit Program — a program that allows medical device regulatory authorities to leverage audits conducted by auditing organisations to satisfy their own regulatory requirements.', source: 'IMDRF', category: 'General Regulatory', aliases: ['Medical Device Single Audit Program'] },
  { term: 'IMDRF', definition: 'International Medical Device Regulators Forum — a voluntary group of medical device regulators from around the world that discusses future directions in medical device regulatory harmonisation and convergence.', source: 'IMDRF', category: 'General Regulatory', aliases: ['International Medical Device Regulators Forum'] },
  { term: 'GLP', definition: 'Good Laboratory Practice — a quality system for non-clinical laboratory studies that ensures the reliability and integrity of data submitted to regulatory agencies.', source: 'OECD / 21 CFR 58', category: 'General Regulatory', aliases: ['Good Laboratory Practice'] },
  { term: 'GCP', definition: 'Good Clinical Practice — an international ethical and scientific quality standard for designing, conducting, recording, and reporting clinical trials that involve human subjects.', source: 'ICH E6', category: 'General Regulatory', aliases: ['Good Clinical Practice'] },
  { term: 'Notified Body Opinion', definition: 'The formal opinion provided by a Notified Body during the conformity assessment process on the compliance of a device\'s technical documentation with MDR requirements.', source: 'MDR', category: 'General Regulatory' },
  { term: 'Technical File', definition: 'The documentation compiling all evidence of a device\'s compliance with regulatory requirements. In EU context, synonymous with Technical Documentation per MDR Annex II/III.', source: 'MDR Annex II', category: 'General Regulatory' },
  { term: 'Regulatory Strategy', definition: 'A documented plan outlining the regulatory pathway, classification, applicable standards, and timeline for obtaining market authorisation across target markets.', source: 'General', category: 'General Regulatory' },
  { term: 'Market Surveillance', definition: 'Activities performed by competent authorities to verify that products on the market comply with applicable EU legislation and to take corrective action where necessary.', source: 'MDR Art. 93', category: 'General Regulatory' },
  { term: 'Harmonised Standard', definition: 'A European standard developed by a recognised European Standards Organisation (CEN, CENELEC, ETSI) and cited in the Official Journal of the EU. Provides presumption of conformity with relevant legislative requirements.', source: 'MDR Art. 8', category: 'General Regulatory', aliases: ['hEN'] },
  { term: 'Gap Analysis', definition: 'A systematic comparison of current documentation, processes, and evidence against regulatory requirements or standard clauses to identify areas needing action (gaps).', source: 'General', category: 'General Regulatory' },
  { term: 'Design Control', definition: 'A systematic approach to managing the design and development process to ensure that the finished device meets user needs and regulatory requirements. Required by both FDA QSR and ISO 13485.', source: 'FDA 21 CFR 820.30 / ISO 13485 §7.3', category: 'General Regulatory' },
  { term: 'V-Model', definition: 'A systems development methodology representing the relationships between development phases (left side) and corresponding testing/verification phases (right side), commonly used in medical device development.', source: 'General', category: 'General Regulatory' },
  { term: 'DHF', definition: 'Design History File — the complete record of a device\'s design and development history, including design inputs, outputs, reviews, verification, validation, and changes. Required by FDA QSR/QMSR.', source: 'FDA 21 CFR 820.40', category: 'General Regulatory', aliases: ['Design History File'] },
  { term: 'ISO', definition: 'International Organization for Standardization — an international standard-setting body composed of representatives from various national standards organisations. Publishes standards relevant to medical devices (13485, 14971, etc.).', source: 'General', category: 'General Regulatory', aliases: ['International Organization for Standardization'] },
  { term: 'IEC', definition: 'International Electrotechnical Commission — an international standards organisation for electrical, electronic, and related technologies. Publishes standards relevant to medical devices (62304, 62366, 60601, etc.).', source: 'General', category: 'General Regulatory', aliases: ['International Electrotechnical Commission'] },
  { term: 'Electromagnetic Compatibility', definition: 'The ability of a device to function satisfactorily in its electromagnetic environment without introducing intolerable electromagnetic disturbances to other equipment in that environment.', source: 'IEC 60601-1-2', category: 'General Regulatory', aliases: ['EMC'] },
  { term: 'Essential Performance', definition: 'Performance of a clinical function, other than that related to basic safety, where loss or degradation beyond the limits specified by the manufacturer results in an unacceptable risk.', source: 'IEC 60601-1 §3.27', category: 'General Regulatory' },
  { term: 'Predicate Search', definition: 'The process of identifying legally marketed devices that may serve as predicates for a 510(k) submission, based on intended use and technological characteristics.', source: 'FDA', category: 'General Regulatory' },
];
